// src/components/VideoDetector.js
import React, { useState } from "react";
import axios from "axios";

const API_URL = "http://127.0.0.1:5000";

function VideoDetector() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [preview, setPreview] = useState(null);

  const handleFileChange = (event) => {
    const uploadedFile = event.target.files[0];
    if (!uploadedFile) return;
    setFile(uploadedFile);
    setResult(null);
    setError("");
    setPreview(URL.createObjectURL(uploadedFile));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (!file) {
      setError("Please select a video file first.");
      return;
    }
    const formData = new FormData();
    formData.append("file", file);
    setIsLoading(true);
    setError("");
    setResult(null);
    try {
      const response = await axios.post(`${API_URL}/predict/video`, formData);
      setResult(response.data);
    } catch (err) {
      setError(
        "An error occurred. Please ensure the backend server is running and try again."
      );
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="detector-container">
      <h2 style={{ textAlign: "center" }}>🎥 Video Deepfake Detector</h2>
      <form onSubmit={handleSubmit} className="detector-form">
        <label htmlFor="file-upload" className="file-input-label">
          <span>{file ? file.name : "Click to Choose a Video"}</span>
          <small style={{ color: "#777" }}> (MP4, MOV)</small>
        </label>
        <input
          id="file-upload"
          type="file"
          onChange={handleFileChange}
          accept="video/mp4,video/quicktime"
        />
        <button type="submit" className="btn" disabled={isLoading || !file}>
          {isLoading ? "Analyzing..." : "Analyze Video"}
        </button>
      </form>

      {isLoading && (
        <div className="spinner-container">
          <div className="spinner"></div>
          <p style={{ marginLeft: "10px" }}>
            Processing video, this may take a moment...
          </p>
        </div>
      )}
      {error && (
        <p style={{ color: "var(--danger-color)", textAlign: "center" }}>
          {error}
        </p>
      )}

      {preview && !result && !isLoading && (
        <div style={{ textAlign: "center", marginTop: "2rem" }}>
          <h3>Video Preview</h3>
          <video
            src={preview}
            controls
            style={{ maxWidth: "80%", maxHeight: "300px", borderRadius: "8px" }}
          />
        </div>
      )}

      {result && (
        <div
          className={`result-card ${
            result.result === "REAL" ? "result-real" : "result-deepfake"
          }`}
        >
          <h4>{result.result}</h4>
          <p>
            The model's raw confidence score is **
            {(result.confidence * 100).toFixed(2)}%**.
          </p>
        </div>
      )}
    </div>
  );
}

export default VideoDetector;
